--
-- Table structure for table `attendance_months`
--

DROP TABLE IF EXISTS `attendance_months`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `attendance_months` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint unsigned NOT NULL,
  `year` int NOT NULL,
  `month` int NOT NULL,
  `total_hours` decimal(10,2) NOT NULL DEFAULT '0.00',
  `total_night_hours` decimal(10,2) NOT NULL DEFAULT '0.00',
  `total_holiday_hours` decimal(10,2) NOT NULL DEFAULT '0.00',
  `suggested_rest_days` int NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `worked_days` int NOT NULL DEFAULT '0',
  `total_holidays` int NOT NULL DEFAULT '0',
  `holidays_worked` int NOT NULL DEFAULT '0',
  `weekend_days` int NOT NULL DEFAULT '0',
  `total_days` int NOT NULL DEFAULT '0',
  `absence_days` int NOT NULL DEFAULT '0',
  `justification_days` int NOT NULL DEFAULT '0',
  `overtime_hours` decimal(5,2) NOT NULL DEFAULT '0.00',
  `late_minutes` int NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
